#include <stdio.h>
#include <stdlib.h>

void gaussJordan(double **A, double *b, int n) {
  // Transform A into reduced row echelon form
  for (int i = 0; i < n; i++) {
    // Search for pivot element
    for (int j = i; j < n; j++) {
      if (A[j][i] != 0) {
        // Swap rows i and j
        double *temp = A[i];
        A[i] = A[j];
        A[j] = temp;
        // Eliminate elements below pivot
        for (int k = i + 1; k < n; k++) {
          double factor = A[k][i] / A[i][i];
          for (int l = i + 1; l <= n; l++) {
            A[k][l] -= factor * A[i][l];
          }
        }
      }
    }
  }
  // Solve for variables
  for (int i = n - 1; i >= 0; i--) {
    b[i] = A[i][n] / A[i][i];
    for (int j = i - 1; j >= 0; j--) {
      A[j][n] -= A[j][i] * b[i];
    }
  }
}

int main() {
  int n = 3;
  double **A = (double **)malloc(n * sizeof(double *));
  for (int i = 0; i < n; i++) {
    A[i] = (double *)malloc((n + 1) * sizeof(double));
  }
  double *b = (double *)malloc(n * sizeof(double));

  // Initialize A and b
  for (int i = 0; i < n; i++) {
    for (int j = 0; j <= n; j++) {
      A[i][j] = 0;
    }
    b[i] = 0;
  }

  // Set up system of linear equations
  A[0][0] = 2;
  A[0][1] = 1;
  A[0][2] = 1;
  A[0][3] = 4;
  A[1][0] = 1;
  A[1][1] = 2;
  A[1][2] = 1;
  A[1][3] = 5;
  A[2][0] = 1;
  A[2][1] = 1;
  A[2][2] = 2;
  A[2][3] = 6;

  gaussJordan(A, b, n);

  // Print solution
  for (int i = 0; i < n; i++) {
    printf("x[%d] = %f\n", i, b[i]);
  }

  return 0;
}
